oxy_webhelp_navlinks = {"viewing_violation_details-d27248e47019":{"topics":[{"title":"Violations page","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Agent Operations<\/span> triggers a violation when it detects configurations that         violate a policy, for example, when it detects a delete_file tool configured on an agent.             <span class=\"ph\">Agent Operations<\/span> triggers an alert when it detects an action that has violated a         policy. Another way to think of the difference is that violations refer to a state of data         analysis and alerts refer to activity or actions on data.<\/p>","href":"agent_operations\/violations_page.html","attributes":{"data-id":"violations_page"},"menu":{"hasChildren":false},"tocID":"violations_page-d27248e47030","topics":[]}]}};